--- detect.go ---
package launch

import (
	"os"
	"os/exec"
)

// KnownAgents is the ordered set of AI coding-agent CLIs wasa probes for on
// PATH. It is the single place to teach wasa a new agent: append the binary
// name and detection follows it. The order is also the presentation order in
// the create-session menu.
var KnownAgents = []string{
	"claude",       // Claude Code
	"codex",        // OpenAI Codex CLI
	"copilot",      // GitHub Copilot CLI
	"gemini",       // Gemini CLI
	"cursor-agent", // Cursor CLI
	"aider",        // Aider
}

// DetectAgents returns the subset of KnownAgents resolvable on PATH, preserving
// KnownAgents order. The result is empty when none of the known agents are
// installed.
func DetectAgents() []string {
	found := make([]string, 0, len(KnownAgents))
	for _, name := range KnownAgents {
		if _, ok := lookAgent(name); ok {
			found = append(found, name)
		}
	}
	return found
}

// lookAgent resolves an agent CLI on PATH via exec.LookPath, returning its full
// path.
func lookAgent(name string) (string, bool) {
	p, err := exec.LookPath(name)
	if err != nil {
		return "", false
	}
	return p, true
}

// Shell returns the OS shell wasa runs for a plain (no-agent) session: $SHELL or
// bash. It is the create flow's fallback when no known agent is installed and
// the explicit menu choice for a bare shell.
func Shell() string {
	if sh := os.Getenv("SHELL"); sh != "" {
		return sh
	}
	return "bash"
}
--- autonomous.go ---
package launch

import (
	"path/filepath"
	"slices"
	"strings"
)

// autonomyFlag is one agent's skip-permissions / "autonomous" configuration: the
// canonical flag wasa appends when the toggle is on, plus aliases — other tokens
// that already imply autonomy, whose presence suppresses the append so wasa never
// double-applies or stacks conflicting flags.
type autonomyFlag struct {
	flag    string
	aliases []string
}

// autonomyFlags maps an agent's base executable to its skip-permissions flag.
// These CLIs move fast; this map is the single place to teach wasa a new agent's
// autonomous flag or adjust an existing one. Keyed by base executable so it
// agrees with KnownAgents and the program picker.
var autonomyFlags = map[string]autonomyFlag{
	"claude": {flag: "--dangerously-skip-permissions"},
	"codex": {
		flag:    "--dangerously-bypass-approvals-and-sandbox",
		aliases: []string{"--yolo", "--full-auto"},
	},
	"gemini": {flag: "--yolo", aliases: []string{"--approval-mode"}},
	"copilot": {
		flag:    "--allow-all-tools",
		aliases: []string{"--allow-all", "--yolo"},
	},
	"cursor-agent": {flag: "--force"},
}

// baseExe reduces a launch program ("/usr/bin/claude --resume") to its base
// executable name ("claude"). It mirrors sessionstatus.toolName so the program
// picker and the flag mapping agree on "the agent" even when the field already
// carries flags.
func baseExe(program string) string {
	program = strings.TrimSpace(program)
	if program == "" {
		return ""
	}
	return filepath.Base(strings.Fields(program)[0])
}

// AutonomousFlag returns the canonical skip-permissions flag for program's base
// executable and whether one is known. A shell or unknown program has no flag.
func AutonomousFlag(program string) (string, bool) {
	a, ok := autonomyFlags[baseExe(program)]
	if !ok {
		return "", false
	}
	return a.flag, true
}

// AutonomousAvailable reports whether program maps to a known autonomous flag. It
// drives the create form's toggle: enabled only when a flag exists to append.
func AutonomousAvailable(program string) bool {
	_, ok := autonomyFlags[baseExe(program)]
	return ok
}

// WithAutonomous returns program with its agent's skip-permissions flag appended.
// It returns program unchanged when no flag is known for the agent, or when the
// program already carries the canonical flag or one of its aliases — so toggling
// autonomous on is idempotent and never stacks conflicting flags onto a command
// the user already wrote by hand.
func WithAutonomous(program string) string {
	a, ok := autonomyFlags[baseExe(program)]
	if !ok {
		return program
	}
	tokens := strings.Fields(program)
	if slices.Contains(tokens, a.flag) {
		return program
	}
	for _, alias := range a.aliases {
		if slices.Contains(tokens, alias) {
			return program
		}
	}
	return strings.TrimSpace(program) + " " + a.flag
}
--- profile.go ---
package profile

import (
	"bufio"
	"bytes"
	"fmt"
	"maps"
	"os"
	"slices"
	"strings"

	"github.com/joakimcarlsson/wasa-cli/internal/registry"
)

// configDirVars maps a program name to the environment variable that overrides
// its config/home directory. It is the single place to teach wasa a new
// program's config-dir convention.
var configDirVars = map[string]string{
	"claude":  "CLAUDE_CONFIG_DIR",
	"copilot": "GH_CONFIG_DIR",
	"gh":      "GH_CONFIG_DIR",
}

// ConfigDirVar returns the config-dir environment variable for program and
// whether one is known. A program with no known convention reports false, and
// its sessions receive no config-dir override.
func ConfigDirVar(program string) (string, bool) {
	v, ok := configDirVars[program]
	return v, ok
}

// Resolve computes the environment to inject into a session launched for
// program under p, as KEY=VALUE entries sorted by key for a deterministic argv.
//
// Precedence, from lowest to highest: env files are loaded first in the order
// listed, each overriding the previous; the inline Env map then overrides any
// value from a file; finally, when AgentConfigDir is set and program has a
// known config-dir variable, that variable is set to AgentConfigDir and
// overrides anything above it, so the per-repository account always wins.
func Resolve(p registry.Profile, program string) ([]string, error) {
	merged := map[string]string{}

	for _, path := range p.EnvFiles {
		vars, err := loadEnvFile(path)
		if err != nil {
			return nil, err
		}
		maps.Copy(merged, vars)
	}

	maps.Copy(merged, p.Env)

	if p.AgentConfigDir != "" {
		if v, ok := ConfigDirVar(program); ok {
			merged[v] = p.AgentConfigDir
		}
	}

	keys := make([]string, 0, len(merged))
	for k := range merged {
		keys = append(keys, k)
	}
	slices.Sort(keys)

	out := make([]string, 0, len(keys))
	for _, k := range keys {
		out = append(out, k+"="+merged[k])
	}
	return out, nil
}

func loadEnvFile(path string) (map[string]string, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("read env file %q: %w", path, err)
	}
	return parseEnvFile(data), nil
}

// parseEnvFile parses standard KEY=VALUE .env lines. Blank lines and lines whose
// first non-space character is '#' are ignored, an optional leading "export " is
// dropped, and a single layer of matching single or double quotes is stripped
// from the value. A line without '=' is skipped.
func parseEnvFile(data []byte) map[string]string {
	out := map[string]string{}
	sc := bufio.NewScanner(bytes.NewReader(data))
	for sc.Scan() {
		line := strings.TrimSpace(sc.Text())
		if line == "" || strings.HasPrefix(line, "#") {
			continue
		}
		line = strings.TrimPrefix(line, "export ")

		key, value, ok := strings.Cut(line, "=")
		if !ok {
			continue
		}
		key = strings.TrimSpace(key)
		if key == "" {
			continue
		}
		out[key] = unquote(strings.TrimSpace(value))
	}
	return out
}

func unquote(s string) string {
	if len(s) >= 2 {
		if (s[0] == '"' && s[len(s)-1] == '"') ||
			(s[0] == '\'' && s[len(s)-1] == '\'') {
			return s[1 : len(s)-1]
		}
	}
	return s
}
--- recorder.go ---
package record

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// hookEvent is one agent hook the recorder subscribes to. end marks the
// event that closes the session, which the installed command flags with
// --event end so the handler needs no per-agent event vocabulary.
type hookEvent struct {
	name string
	end  bool
}

// Recorder is one agent's recording integration: how to install, remove and
// detect its hook configuration, where to find its transcript, how to resume
// it natively, and how to read its native transcript into the common message
// shape. It is the only agent-aware seam in the recorder — everything else
// operates on the normalized shape or on Meta.Agent, so a new agent is one
// file implementing this interface plus an entry in recorders.
type Recorder interface {
	// Tool is the --tool value and the agent name recorded in meta.json.
	Tool() string
	// Exe is the base executable that selects this agent at launch.
	Exe() string
	// InstallHooks merges the recording hooks into dir's agent configuration.
	InstallHooks(dir, wasaExe string) error
	// RemoveHooks strips the recording hooks from dir's agent configuration.
	RemoveHooks(dir string) error
	// HooksInstalled reports whether dir carries the recording hooks.
	HooksInstalled(dir string) bool
	// LocateTranscript best-effort finds the agent's existing transcript for a
	// session when a hook payload did not name it, or "" when none is present.
	LocateTranscript(sessionID, repoDir string) string
	// TranscriptTarget computes where the agent's transcript for a session
	// would live without checking that it exists, so a resumed session can
	// restore a recorded transcript there before a native resume. "" means the
	// agent has no deterministic single-file transcript, so a session with no
	// live local transcript falls back to the checkpoint preamble.
	TranscriptTarget(sessionID, repoDir string) string
	// ResumeArgs returns the argv appended to the launch program to continue a
	// prior session natively (e.g. {"--resume", id}), or nil for an agent with
	// no CLI resume.
	ResumeArgs(sessionID string) []string
	// Normalize maps the agent's native transcript to the common message shape,
	// one Message per native line, preserving order and the raw bytes.
	Normalize(native []byte) []Message
	// Intent extracts the first real user prompt from the native transcript:
	// the intent that started the session, or "" when there is none.
	Intent(native []byte) string
}

// recorders are the supported recording integrations. Event choices per agent:
// a prompt-bearing event early (intent), a per-tool or per-turn event
// (commit detection) and, where the agent offers one, a session-end event
// (closing checkpoint for unmanaged sessions; Codex has none, so unmanaged
// Codex sessions close only through wasa finish).
var recorders = []Recorder{
	claudeRecorder{},
	geminiRecorder{},
	codexRecorder{},
	copilotRecorder{},
	cursorRecorder{},
}

// recorderFor returns the integration for a --tool value.
func recorderFor(tool string) (Recorder, bool) {
	for _, r := range recorders {
		if r.Tool() == tool {
			return r, true
		}
	}
	return nil, false
}

// AgentForProgram returns the recording tool name for a launch program
// ("/usr/bin/cursor-agent --foo" → "cursor"), or false when the agent has no
// recording integration.
func AgentForProgram(program string) (string, bool) {
	exe := baseExe(program)
	for _, r := range recorders {
		if r.Exe() == exe {
			return r.Tool(), true
		}
	}
	return "", false
}

// resumeFlag is the common native-resume argv "--resume <id>", shared by the
// agents whose CLI resumes a session that way (claude, gemini, copilot).
func resumeFlag(id string) []string { return []string{"--resume", id} }

// ResumeArgs returns the argv to append to a launch program so its agent
// continues the session agentSessionID natively (e.g. {"--resume", id}), and
// whether that agent supports native resume at all. An empty agentSessionID or
// an agent with no CLI resume reports false, and the caller falls back to the
// checkpoint preamble.
func ResumeArgs(program, agentSessionID string) ([]string, bool) {
	if agentSessionID == "" {
		return nil, false
	}
	tool, ok := AgentForProgram(program)
	if !ok {
		return nil, false
	}
	r, _ := recorderFor(tool)
	args := r.ResumeArgs(agentSessionID)
	if args == nil {
		return nil, false
	}
	return args, true
}

// LocalTranscript returns the path to the live local transcript program's agent
// keeps for agentSessionID under worktreePath, or "" when none is present. A
// present transcript means a native resume can continue without restoring
// anything.
func LocalTranscript(program, agentSessionID, worktreePath string) string {
	tool, ok := AgentForProgram(program)
	if !ok || agentSessionID == "" {
		return ""
	}
	r, _ := recorderFor(tool)
	return r.LocateTranscript(agentSessionID, worktreePath)
}

// RestoreTranscript writes the recorded transcript to where program's agent
// expects it for agentSessionID under worktreePath, so a native resume finds it
// when the live local transcript is gone (e.g. resuming on another machine).
// data is the stored (normalized) transcript; it is converted back to the
// agent's native bytes before writing. It errors when the agent has no
// deterministic transcript path — the caller then falls back to the checkpoint
// preamble rather than a native resume.
func RestoreTranscript(
	program, agentSessionID, worktreePath string, data []byte,
) error {
	tool, ok := AgentForProgram(program)
	if !ok {
		return fmt.Errorf("unknown agent for program %q", program)
	}
	r, _ := recorderFor(tool)
	if agentSessionID == "" {
		return fmt.Errorf("agent %q has no restorable transcript path", tool)
	}
	path := r.TranscriptTarget(agentSessionID, worktreePath)
	if path == "" {
		return fmt.Errorf("agent %q has no restorable transcript path", tool)
	}
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return err
	}
	return os.WriteFile(path, denormalize(data), 0o644)
}

// InstallHooks installs tool's recording hooks into dir, a repository root
// or worktree.
func InstallHooks(dir, tool, wasaExe string) error {
	r, ok := recorderFor(tool)
	if !ok {
		return nil
	}
	return r.InstallHooks(dir, wasaExe)
}

// RemoveHooks strips every agent's recording hooks from dir.
func RemoveHooks(dir string) error {
	for _, r := range recorders {
		if err := r.RemoveHooks(dir); err != nil {
			return err
		}
	}
	return nil
}

// InstalledAgents lists the agents whose recording hooks are present in dir.
func InstalledAgents(dir string) []string {
	var tools []string
	for _, r := range recorders {
		if r.HooksInstalled(dir) {
			tools = append(tools, r.Tool())
		}
	}
	return tools
}

// DetectedAgents lists the supported agents found on PATH, which is what
// repo-level enable installs for.
func DetectedAgents() []string {
	var tools []string
	for _, r := range recorders {
		if _, err := exec.LookPath(r.Exe()); err == nil {
			tools = append(tools, r.Tool())
		}
	}
	return tools
}

// executablePath and detectAgents are indirected so tests can drive Enable
// without a real agent binary on PATH (mirrors the startFinalize seam).
var (
	executablePath = os.Executable
	detectAgents   = DetectedAgents
)

// Enable turns on repo-level recording for dir: it installs recording hooks for
// every supported agent found on PATH and returns the tool names it wired. An
// empty slice with a nil error means no supported agent was detected — callers
// decide how to surface that (the CLI errors, the TUI shows a transient
// message). This is the one shared enable recipe; both the `wasa record enable`
// command and the TUI toggle call it so the two never drift.
func Enable(dir string) ([]string, error) {
	exe, err := executablePath()
	if err != nil {
		return nil, err
	}
	tools := detectAgents()
	if len(tools) == 0 {
		return nil, nil
	}
	for _, tool := range tools {
		if err := InstallHooks(dir, tool, exe); err != nil {
			return nil, fmt.Errorf("%s: %w", tool, err)
		}
	}
	return tools, nil
}

// fallbackTranscript best-effort locates a transcript for sessions whose
// hook payloads never carried a path (Cursor and Copilot omit it on some
// events; a Codex payload may null it).
func fallbackTranscript(tool, sessionID, repoDir string) string {
	r, ok := recorderFor(tool)
	if !ok || sessionID == "" {
		return ""
	}
	return r.LocateTranscript(sessionID, repoDir)
}

// intentFrom extracts the session intent from a native transcript using the
// agent's own parser, or "" when the agent is unknown or the transcript holds
// no user text.
func intentFrom(tool string, native []byte) string {
	r, ok := recorderFor(tool)
	if !ok {
		return ""
	}
	return r.Intent(native)
}

// agentHome resolves an agent's data directory: envKey when set (and
// non-empty), else homeSub under the user's home directory.
func agentHome(envKey, homeSub string) string {
	if envKey != "" {
		if v := os.Getenv(envKey); v != "" {
			return v
		}
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return homeSub
	}
	return filepath.Join(home, homeSub)
}

// sanitizePath mirrors the path munging Claude Code and Cursor use for their
// per-project transcript directories: every non-alphanumeric byte becomes
// a dash.
func sanitizePath(p string) string {
	return strings.Map(func(r rune) rune {
		switch {
		case r >= 'a' && r <= 'z', r >= 'A' && r <= 'Z', r >= '0' && r <= '9':
			return r
		}
		return '-'
	}, p)
}

func existing(path string) string {
	if _, err := os.Stat(path); err != nil {
		return ""
	}
	return path
}
