func TestConfigDirVar(t *testing.T) {
	cases := []struct {
		program string
		want    string
		wantOK  bool
	}{
		{"claude", "CLAUDE_CONFIG_DIR", true},
		{"copilot", "GH_CONFIG_DIR", true},
		{"gh", "GH_CONFIG_DIR", true},
		{"bash", "", false},
		{"", "", false},
	}

	for _, tc := range cases {
		t.Run(tc.program, func(t *testing.T) {
			got, ok := ConfigDirVar(tc.program)
			if got != tc.want || ok != tc.wantOK {
				t.Fatalf(
					"ConfigDirVar(%q) = (%q, %v), want (%q, %v)",
					tc.program, got, ok, tc.want, tc.wantOK,
				)
			}
		})
	}
}

func TestParseEnvFile(t *testing.T) {
	data := []byte(
		"# a comment\n" +
---
// Package profile resolves a workspace profile into the concrete environment
// injected into a session at launch. It loads the profile's env files from
// disk, merges them with the profile's inline env map and the per-program
// config-dir override, and returns the result as KEY=VALUE entries ready to
// hand to tmux as new-session -e arguments.
//
// Secrets live in env files and are read only here, at launch time; this
// package never writes them back into wasa's persisted state, which stores only
// the env-file paths.
package profile
---HANDLE---
// it writes s's closing checkpoint against repoDir (empty for a plain
// session outside any workspace, in which case the hook-reported state fills
// in what it can) and degrades any failure to a single logged warning, so
// recording can never fail a teardown.
func FinishSession(home, repoDir string, s *registry.Session) {
	if s == nil {
		return
	}
	err := Finish(home, FinishInfo{
		SessionID:   s.ID,
		WorkspaceID: s.WorkspaceID,
		Program:     s.Program,
		Branch:      s.Branch,
		BaseCommit:  s.BaseCommit,
		RepoDir:     repoDir,
		StartedAt:   s.CreatedAt,
		ResumedFrom: s.ResumedFrom,
	})
	if err != nil {
		log.Printf("wasa: session %s not recorded: %v", s.ID, err)
	}
}

// baseExe reduces a launch program ("/usr/bin/claude --resume") to its base
// executable name ("claude"), the value recorded as the agent.
func baseExe(program string) string {
	program = strings.TrimSpace(program)
	if program == "" {
		return ""
	}
	return filepath.Base(strings.Fields(program)[0])
}
